import{_ as o,o as a,c as t,ai as n}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Network model","description":"","frontmatter":{"summary":"How the Gateway, nodes, and canvas host connect.","read_when":["You want a concise view of the Gateway networking model"],"title":"Network model"},"headers":[],"relativePath":"gateway/network-model.md","filePath":"gateway/network-model.md","lastUpdated":null}'),s={name:"gateway/network-model.md"};function r(l,e,c,i,d,w){return a(),t("div",null,[...e[0]||(e[0]=[n('<p>Most operations flow through the Gateway (<code>opensoul gateway</code>), a single long-running process that owns channel connections and the WebSocket control plane.</p><h2 id="core-rules" tabindex="-1"><a class="header-anchor" href="#core-rules">#</a> Core rules</h2><ul><li>One Gateway per host is recommended. It is the only process allowed to own the WhatsApp Web session. For rescue bots or strict isolation, run multiple gateways with isolated profiles and ports. See <a href="/docs/gateway/multiple-gateways">Multiple gateways</a>.</li><li>Loopback first: the Gateway WS defaults to <code>ws://127.0.0.1:18789</code>. The wizard generates a gateway token by default, even for loopback. For tailnet access, run <code>opensoul gateway --bind tailnet --token ...</code> because tokens are required for non-loopback binds.</li><li>Nodes connect to the Gateway WS over LAN, tailnet, or SSH as needed. The legacy TCP bridge is deprecated.</li><li>Canvas host is an HTTP file server on <code>canvasHost.port</code> (default <code>18793</code>) serving <code>/__opensoul__/canvas/</code> for node WebViews. See <a href="/docs/gateway/configuration">Gateway configuration</a> (<code>canvasHost</code>).</li><li>Remote use is typically SSH tunnel or tailnet VPN. See <a href="/docs/gateway/remote">Remote access</a> and <a href="/docs/gateway/discovery">Discovery</a>.</li></ul>',3)])])}const h=o(s,[["render",r]]);export{u as __pageData,h as default};
